const SOUND_MAKABHOSDA = 'data:audio/mp3;base64,';
const SOUND_ANIMEAHH = 'data:audio/mp3;base64,';
const SOUND_MODIJI = 'data:audio/mp3;base64,';

// ═══════════════════════════════════════════════════════════════
//  FLAPPY MAKA AAAAAG — Complete Game Engine
// ═══════════════════════════════════════════════════════════════

const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

// ── Responsive sizing ──
const BASE_W = 400, BASE_H = 600;
let scale = 1;
function resize() {
  const maxH = window.innerHeight - 20, maxW = window.innerWidth - 10;
  scale = Math.min(maxW / BASE_W, maxH / BASE_H, 1.6);
  canvas.width = BASE_W; canvas.height = BASE_H;
  canvas.style.width = (BASE_W * scale) + 'px';
  canvas.style.height = (BASE_H * scale) + 'px';
}
resize();
window.addEventListener('resize', resize);

// ── Audio System ───────────────────────────────────────────────
let audioCtx = null;
let musicPlaying = false;
let musicNodes = {};
let audioReady = false;
let modiPlayed = false;

// Pre-load Audio elements for the real sound files
const sfxMaka    = new Audio(SOUND_MAKABHOSDA);
const sfxAnime   = new Audio(SOUND_ANIMEAHH);
const sfxModi    = new Audio(SOUND_MODIJI);
sfxMaka.preload  = 'auto';
sfxAnime.preload = 'auto';
sfxModi.preload  = 'auto';
sfxAnime.volume  = 0.85;
sfxMaka.volume   = 1.0;
sfxModi.volume   = 0.7;

function playAnimeAhh() {
  sfxAnime.currentTime = 0;
  sfxAnime.play().catch(() => {});
}
function playMakaBhosda() {
  sfxMaka.currentTime = 0;
  sfxMaka.play().catch(() => {});
}
function playModiJi() {
  if (modiPlayed) return;
  modiPlayed = true;
  sfxModi.currentTime = 0;
  sfxModi.play().catch(() => {});
}

function initAudio() {
  if (audioCtx) return;
  audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  audioReady = true;
}

function playPoint() {
  if (!audioReady) return;
  [523, 659, 784].forEach((freq, i) => {
    const o = audioCtx.createOscillator(), g = audioCtx.createGain();
    o.connect(g); g.connect(audioCtx.destination);
    o.type = 'square'; o.frequency.value = freq;
    g.gain.setValueAtTime(0.1, audioCtx.currentTime + i * 0.07);
    g.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + i * 0.07 + 0.1);
    o.start(audioCtx.currentTime + i * 0.07);
    o.stop(audioCtx.currentTime + i * 0.07 + 0.1);
  });
}

function playCountdownBeep(final) {
  if (!audioReady) return;
  const o = audioCtx.createOscillator(), g = audioCtx.createGain();
  o.connect(g); g.connect(audioCtx.destination);
  o.type = 'sine';
  o.frequency.value = final ? 880 : 440;
  g.gain.setValueAtTime(0.3, audioCtx.currentTime);
  g.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + (final ? 0.5 : 0.2));
  o.start(); o.stop(audioCtx.currentTime + (final ? 0.5 : 0.2));
}

function startMusic() {
  if (!audioReady || musicPlaying) return;
  musicPlaying = true;
  const gainNode = audioCtx.createGain();
  gainNode.gain.value = 0.12;
  gainNode.connect(audioCtx.destination);
  const melody = [523, 587, 659, 698, 784, 698, 659, 587, 523, 494, 523, 587];
  const bassLine = [130, 146, 165, 174, 196, 174, 165, 146];
  let step = 0, bassStep = 0;
  const tempo = 0.22;
  function playMelodyNote() {
    if (!musicPlaying) return;
    const o = audioCtx.createOscillator(), g = audioCtx.createGain();
    o.connect(g); g.connect(gainNode);
    o.type = 'triangle'; o.frequency.value = melody[step % melody.length];
    g.gain.setValueAtTime(0.5, audioCtx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + tempo * 0.8);
    o.start(); o.stop(audioCtx.currentTime + tempo * 0.8);
    step++;
    musicNodes.melodyTimer = setTimeout(playMelodyNote, tempo * 1000);
  }
  function playBassNote() {
    if (!musicPlaying) return;
    const o = audioCtx.createOscillator(), g = audioCtx.createGain();
    o.connect(g); g.connect(gainNode);
    o.type = 'square'; o.frequency.value = bassLine[bassStep % bassLine.length];
    g.gain.setValueAtTime(0.3, audioCtx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + tempo * 1.6);
    o.start(); o.stop(audioCtx.currentTime + tempo * 1.6);
    bassStep++;
    musicNodes.bassTimer = setTimeout(playBassNote, tempo * 2000);
  }
  playMelodyNote();
  setTimeout(playBassNote, tempo * 500);
}
function stopMusic() {
  musicPlaying = false;
  clearTimeout(musicNodes.melodyTimer);
  clearTimeout(musicNodes.bassTimer);
}

// ── Sprite Drawing ─────────────────────────────────────────────
function drawMaka(x, y, angle, flapFrame, isDead) {
  ctx.save();
  ctx.translate(x, y);
  ctx.rotate(angle);
  const s = 1;
  ctx.fillStyle = isDead ? '#999' : '#F5C842';
  ctx.beginPath(); ctx.ellipse(0, 4*s, 18*s, 22*s, 0, 0, Math.PI*2); ctx.fill();
  ctx.fillStyle = isDead ? '#777' : '#E0A820';
  ctx.fillRect(-6*s, -4*s, 12*s, 16*s);
  ctx.fillStyle = isDead ? '#888' : '#D4922A';
  ctx.beginPath(); ctx.moveTo(-6*s,-4*s); ctx.lineTo(0,4*s); ctx.lineTo(6*s,-4*s); ctx.closePath(); ctx.fill();
  ctx.fillStyle = isDead ? '#C4A882' : '#D4A574';
  ctx.beginPath(); ctx.ellipse(0,-16*s,15*s,18*s,0,0,Math.PI*2); ctx.fill();
  ctx.fillStyle = isDead ? '#333' : '#1a1a1a';
  ctx.beginPath(); ctx.ellipse(0,-26*s,15*s,10*s,0,Math.PI,Math.PI*2); ctx.fill();
  ctx.beginPath(); ctx.ellipse(-12*s,-22*s,6*s,8*s,-0.3,0,Math.PI*2); ctx.fill();
  ctx.beginPath(); ctx.ellipse(12*s,-22*s,6*s,8*s,0.3,0,Math.PI*2); ctx.fill();
  ctx.fillStyle = isDead ? '#555' : '#2a2a2a';
  ctx.beginPath(); ctx.ellipse(-5*s,-9*s,6*s,3*s,-0.2,0,Math.PI*2); ctx.fill();
  ctx.beginPath(); ctx.ellipse(5*s,-9*s,6*s,3*s,0.2,0,Math.PI*2); ctx.fill();
  ctx.fillStyle = '#aaa';
  ctx.beginPath(); ctx.ellipse(-4*s,-9*s,3*s,1.5*s,-0.2,0,Math.PI*2); ctx.fill();
  ctx.beginPath(); ctx.ellipse(6*s,-9*s,3*s,1.5*s,0.2,0,Math.PI*2); ctx.fill();
  ctx.fillStyle = 'white';
  ctx.beginPath(); ctx.ellipse(-5*s,-16*s,5*s,5*s,0,0,Math.PI*2); ctx.fill();
  ctx.beginPath(); ctx.ellipse(5*s,-16*s,5*s,5*s,0,0,Math.PI*2); ctx.fill();
  ctx.fillStyle = isDead ? 'white' : '#3a1a0a';
  const pupilY = isDead ? -16*s : -17*s + Math.sin(flapFrame*0.3)*1;
  ctx.beginPath(); ctx.ellipse(-5*s,pupilY,3*s,3*s,0,0,Math.PI*2); ctx.fill();
  ctx.beginPath(); ctx.ellipse(5*s,pupilY,3*s,3*s,0,0,Math.PI*2); ctx.fill();
  if (isDead) {
    ctx.strokeStyle='#ff0000'; ctx.lineWidth=2;
    ctx.beginPath(); ctx.moveTo(-8*s,-19*s); ctx.lineTo(-2*s,-13*s); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(-2*s,-19*s); ctx.lineTo(-8*s,-13*s); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(2*s,-19*s); ctx.lineTo(8*s,-13*s); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(8*s,-19*s); ctx.lineTo(2*s,-13*s); ctx.stroke();
  } else {
    ctx.fillStyle='white';
    ctx.beginPath(); ctx.ellipse(-4*s,-17*s,1.5*s,1.5*s,0,0,Math.PI*2); ctx.fill();
    ctx.beginPath(); ctx.ellipse(6*s,-17*s,1.5*s,1.5*s,0,0,Math.PI*2); ctx.fill();
  }
  ctx.strokeStyle = isDead ? '#444' : '#1a1a1a'; ctx.lineWidth=3*s; ctx.lineCap='round';
  const browY = isDead ? -23*s : -22*s - Math.abs(Math.sin(flapFrame*0.5))*2;
  ctx.beginPath(); ctx.moveTo(-9*s,browY); ctx.quadraticCurveTo(-5*s,browY-3*s,-1*s,browY); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(9*s,browY); ctx.quadraticCurveTo(5*s,browY-3*s,1*s,browY); ctx.stroke();
  ctx.strokeStyle='#8B4513'; ctx.lineWidth=2*s;
  if (isDead) {
    ctx.beginPath(); ctx.moveTo(-6*s,-5*s); ctx.quadraticCurveTo(0,-9*s,6*s,-5*s); ctx.stroke();
  } else if (flapFrame%30<15) {
    ctx.fillStyle='#cc4400';
    ctx.beginPath(); ctx.ellipse(0,-5*s,4*s,3*s,0,0,Math.PI*2); ctx.fill();
  } else {
    ctx.beginPath(); ctx.moveTo(-5*s,-5*s); ctx.quadraticCurveTo(0,-3*s,5*s,-5*s); ctx.stroke();
  }
  const wingAngle = Math.sin(flapFrame*0.5)*0.6;
  ctx.save(); ctx.translate(-18*s,2*s); ctx.rotate(-wingAngle-0.3);
  ctx.fillStyle = isDead?'#aaa':'#F5C842';
  ctx.beginPath(); ctx.ellipse(0,0,8*s,4*s,0.4,0,Math.PI*2); ctx.fill(); ctx.restore();
  ctx.save(); ctx.translate(18*s,2*s); ctx.rotate(wingAngle+0.3);
  ctx.fillStyle = isDead?'#aaa':'#F5C842';
  ctx.beginPath(); ctx.ellipse(0,0,8*s,4*s,-0.4,0,Math.PI*2); ctx.fill(); ctx.restore();
  ctx.strokeStyle = isDead?'#444':'#3a1a00'; ctx.lineWidth=2*s;
  ctx.beginPath(); ctx.ellipse(0,-16*s,15*s,18*s,0,0,Math.PI*2); ctx.stroke();
  ctx.restore();
}

function drawPipe(x, topHeight, gapSize) {
  const pipeW=56, capH=20, capW=64;
  const botY = topHeight + gapSize;
  const botH = BASE_H - botY;
  const grad1 = ctx.createLinearGradient(x,0,x+pipeW,0);
  grad1.addColorStop(0,'#e8a830'); grad1.addColorStop(0.3,'#ffd060');
  grad1.addColorStop(0.7,'#e8a830'); grad1.addColorStop(1,'#c07820');
  ctx.fillStyle=grad1; ctx.fillRect(x,0,pipeW,topHeight);
  ctx.fillStyle='rgba(255,255,255,0.15)';
  for(let sy=0;sy<topHeight;sy+=30) ctx.fillRect(x+8,sy,pipeW-16,10);
  const grad2 = ctx.createLinearGradient(x-4,0,x+capW-4,0);
  grad2.addColorStop(0,'#f0b840'); grad2.addColorStop(0.3,'#ffdf80');
  grad2.addColorStop(0.7,'#f0b840'); grad2.addColorStop(1,'#c88020');
  ctx.fillStyle=grad2;
  ctx.beginPath(); ctx.roundRect(x-4,topHeight-capH,capW,capH,[0,0,6,6]); ctx.fill();
  ctx.strokeStyle='#a06010'; ctx.lineWidth=2;
  ctx.beginPath(); ctx.roundRect(x-4,topHeight-capH,capW,capH,[0,0,6,6]); ctx.stroke();
  ctx.fillStyle=grad1; ctx.fillRect(x,botY,pipeW,botH);
  ctx.fillStyle='rgba(255,255,255,0.15)';
  for(let sy=botY;sy<BASE_H;sy+=30) ctx.fillRect(x+8,sy,pipeW-16,10);
  ctx.fillStyle=grad2;
  ctx.beginPath(); ctx.roundRect(x-4,botY,capW,capH,[6,6,0,0]); ctx.fill();
  ctx.strokeStyle='#a06010'; ctx.lineWidth=2;
  ctx.beginPath(); ctx.roundRect(x-4,botY,capW,capH,[6,6,0,0]); ctx.stroke();
  ctx.strokeStyle='#a06010'; ctx.lineWidth=2;
  ctx.strokeRect(x,0,pipeW,topHeight); ctx.strokeRect(x,botY,pipeW,botH);
  drawStar(x+capW/2-4, topHeight-capH/2, 7,'#ff4400','#ffcc00');
  drawStar(x+capW/2-4, botY+capH/2, 7,'#ff4400','#ffcc00');
}

function drawStar(cx,cy,r,col1,col2){
  ctx.save(); ctx.translate(cx,cy); ctx.fillStyle=col2;
  ctx.beginPath();
  for(let i=0;i<5;i++){
    const a=(i*4*Math.PI/5)-Math.PI/2, b=(i*4*Math.PI/5)+Math.PI/5-Math.PI/2;
    if(i===0) ctx.moveTo(Math.cos(a)*r,Math.sin(a)*r);
    else ctx.lineTo(Math.cos(a)*r,Math.sin(a)*r);
    ctx.lineTo(Math.cos(b)*(r*0.4),Math.sin(b)*(r*0.4));
  }
  ctx.closePath(); ctx.fill();
  ctx.strokeStyle=col1; ctx.lineWidth=1; ctx.stroke(); ctx.restore();
}

// ── Background ─────────────────────────────────────────────────
const clouds=[];
for(let i=0;i<8;i++) clouds.push({x:Math.random()*BASE_W,y:40+Math.random()*(BASE_H*0.5),w:60+Math.random()*80,speed:0.3+Math.random()*0.5,opacity:0.4+Math.random()*0.4});

function drawBackground(bgScroll){
  const sky=ctx.createLinearGradient(0,0,0,BASE_H);
  sky.addColorStop(0,'#1a0832'); sky.addColorStop(0.3,'#3d1060');
  sky.addColorStop(0.6,'#7a2880'); sky.addColorStop(0.8,'#c44060'); sky.addColorStop(1,'#ff8050');
  ctx.fillStyle=sky; ctx.fillRect(0,0,BASE_W,BASE_H);
  const cityX=(bgScroll*0.4)%BASE_W;
  drawCitySilhouette(-cityX); drawCitySilhouette(BASE_W-cityX);
  ctx.fillStyle='rgba(255,255,200,0.8)';
  const starSeed=Math.floor(bgScroll/BASE_W);
  for(let i=0;i<20;i++){
    const sx=((i*137+starSeed*31)%BASE_W), sy=(i*73)%(BASE_H*0.45);
    const pulse=0.5+0.5*Math.sin(Date.now()*0.002+i);
    ctx.globalAlpha=pulse*0.7;
    ctx.beginPath(); ctx.arc(sx,sy,1.5,0,Math.PI*2); ctx.fill();
  }
  ctx.globalAlpha=1;
  clouds.forEach(c=>{
    ctx.globalAlpha=c.opacity*0.6; ctx.fillStyle='#ff9070';
    ctx.beginPath(); ctx.ellipse(c.x,c.y,c.w,c.w*0.4,0,0,Math.PI*2); ctx.fill();
    ctx.beginPath(); ctx.ellipse(c.x-c.w*0.3,c.y+5,c.w*0.6,c.w*0.3,0,0,Math.PI*2); ctx.fill();
    ctx.beginPath(); ctx.ellipse(c.x+c.w*0.3,c.y+5,c.w*0.6,c.w*0.3,0,0,Math.PI*2); ctx.fill();
  });
  ctx.globalAlpha=1;
  const groundGrad=ctx.createLinearGradient(0,BASE_H-80,0,BASE_H);
  groundGrad.addColorStop(0,'#2a4a10'); groundGrad.addColorStop(0.5,'#3a6a18'); groundGrad.addColorStop(1,'#1a3008');
  ctx.fillStyle=groundGrad; ctx.fillRect(0,BASE_H-80,BASE_W,80);
  const gx=(bgScroll*1.5)%40;
  ctx.strokeStyle='#4a8a20'; ctx.lineWidth=1;
  for(let gxi=-40;gxi<BASE_W+40;gxi+=40){
    ctx.beginPath(); ctx.moveTo(gxi-gx,BASE_H-80); ctx.lineTo(gxi-gx,BASE_H); ctx.stroke();
  }
}

function drawCitySilhouette(offsetX){
  const buildings=[{x:0,w:40,h:120},{x:35,w:30,h:160},{x:60,w:50,h:100},{x:105,w:35,h:180},{x:135,w:45,h:130},{x:175,w:30,h:150},{x:200,w:55,h:110},{x:250,w:40,h:170},{x:285,w:35,h:140},{x:315,w:60,h:120},{x:370,w:30,h:160}];
  ctx.fillStyle='rgba(10,5,30,0.85)';
  buildings.forEach(b=>{
    const bx=offsetX+b.x, by=BASE_H-80-b.h;
    ctx.fillRect(bx,by,b.w,b.h);
    ctx.fillStyle='rgba(255,220,80,0.5)';
    for(let wy=by+10;wy<BASE_H-90;wy+=18)
      for(let wx=bx+5;wx<bx+b.w-5;wx+=12)
        if(Math.sin(wx*7+wy*13)>0) ctx.fillRect(wx,wy,6,8);
    ctx.fillStyle='rgba(10,5,30,0.85)';
  });
}

// ── Particles ──────────────────────────────────────────────────
const particles=[];
function spawnParticles(x,y,count,colors,spread=60,speed=4){
  for(let i=0;i<count;i++){
    const angle=Math.random()*Math.PI*2, spd=1+Math.random()*speed;
    particles.push({x,y,vx:Math.cos(angle)*spd,vy:Math.sin(angle)*spd-2,life:1,decay:0.02+Math.random()*0.03,size:3+Math.random()*spread*0.15,color:colors[Math.floor(Math.random()*colors.length)],gravity:0.15});
  }
}
function updateParticles(){
  for(let i=particles.length-1;i>=0;i--){
    const p=particles[i]; p.x+=p.vx; p.y+=p.vy; p.vy+=p.gravity; p.life-=p.decay;
    if(p.life<=0) particles.splice(i,1);
  }
}
function drawParticles(){
  particles.forEach(p=>{ ctx.globalAlpha=p.life; ctx.fillStyle=p.color; ctx.beginPath(); ctx.arc(p.x,p.y,p.size,0,Math.PI*2); ctx.fill(); });
  ctx.globalAlpha=1;
}

// ── Score Popups ───────────────────────────────────────────────
const scorePopups=[];
function addScorePopup(x,y,text){ scorePopups.push({x,y,text,life:1,vy:-1.5}); }
function updateScorePopups(){ for(let i=scorePopups.length-1;i>=0;i--){ scorePopups[i].y+=scorePopups[i].vy; scorePopups[i].life-=0.025; if(scorePopups[i].life<=0) scorePopups.splice(i,1); } }
function drawScorePopups(){ scorePopups.forEach(p=>{ ctx.globalAlpha=p.life; ctx.fillStyle='#FFD700'; ctx.strokeStyle='#FF4400'; ctx.lineWidth=3; ctx.font='bold 20px Arial Black'; ctx.textAlign='center'; ctx.strokeText(p.text,p.x,p.y); ctx.fillText(p.text,p.x,p.y); }); ctx.globalAlpha=1; }

let shakeAmount=0;
function addShake(amt){ shakeAmount=Math.max(shakeAmount,amt); }

// ── Game State ─────────────────────────────────────────────────
const STATE={TITLE:0, COUNTDOWN:1, PLAYING:2, DEAD:3};
let state=STATE.TITLE;

let bird={x:80,y:BASE_H/2,vy:0,angle:0};
const GRAVITY=0.45, FLAP_STRENGTH=-8.5;

let pipes=[];
const PIPE_W=56, GAP_BASE=160, PIPE_SPEED_BASE=2.2;
let pipeSpeed=PIPE_SPEED_BASE, pipeTimer=0;
const PIPE_INTERVAL=90;

let score=0;
let highScore=parseInt(localStorage.getItem('fma_hs')||'0');
let flapFrame=0, bgScroll=0, frame=0, gameOverTimer=0, titleBounce=0, lastMilestone=0;

// Countdown state
let countdownValue=3;     // 3, 2, 1, GO
let countdownTimer=0;     // frames per count
const COUNTDOWN_FRAMES=60; // 1 second each

// ── Input ──────────────────────────────────────────────────────
function doFlap(){
  initAudio();

  if(state===STATE.TITLE){
    // Start countdown instead of game directly
    state=STATE.COUNTDOWN;
    countdownValue=3;
    countdownTimer=0;
    playCountdownBeep(false);
    return;
  }
  if(state===STATE.COUNTDOWN) return; // ignore taps during countdown
  if(state===STATE.DEAD){
    if(gameOverTimer>40){ state=STATE.TITLE; stopMusic(); }
    return;
  }
  if(state===STATE.PLAYING){
    bird.vy=FLAP_STRENGTH;
    playAnimeAhh();  // 🎵 ANIME AHH on every flap
    spawnParticles(bird.x-20,bird.y+10,6,['#FFD700','#FF8800','#FFFFFF'],20,3);
    flapFrame=0;
  }
}

document.addEventListener('keydown',e=>{ if(e.code==='Space'||e.code==='ArrowUp'||e.code==='Enter'){ e.preventDefault(); doFlap(); } });
canvas.addEventListener('click',doFlap);
canvas.addEventListener('touchstart',e=>{ e.preventDefault(); doFlap(); },{passive:false});

// ── Game Logic ─────────────────────────────────────────────────
function resetGame(){
  bird={x:80,y:BASE_H/2,vy:0,angle:0};
  pipes=[]; score=0; pipeSpeed=PIPE_SPEED_BASE;
  pipeTimer=0; frame=0; particles.length=0; scorePopups.length=0; lastMilestone=0;
}

function spawnPipe(){
  const minTop=80, maxTop=BASE_H-80-GAP_BASE-80;
  const gap=GAP_BASE-Math.min(score*0.5,40);
  const topH=minTop+Math.random()*(maxTop-minTop);
  pipes.push({x:BASE_W+10,topH,gap,scored:false});
}

function checkCollision(){
  const bx=bird.x,by=bird.y,br=16;
  if(by-br<0||by+br>BASE_H-80) return true;
  for(const p of pipes){
    const px=p.x-4,pw=PIPE_W+8;
    if(bx+br>px&&bx-br<px+pw) if(by-br<p.topH||by+br>p.topH+p.gap) return true;
  }
  return false;
}

function updateCountdown(){
  countdownTimer++;
  bgScroll+=0.5;
  clouds.forEach(c=>{ c.x-=c.speed; if(c.x<-c.w) c.x=BASE_W+c.w; });

  if(countdownTimer>=COUNTDOWN_FRAMES){
    countdownTimer=0;
    countdownValue--;
    if(countdownValue===0){
      // GO! Start the game
      playCountdownBeep(true);
      state=STATE.PLAYING;
      resetGame();
      startMusic();
    } else {
      playCountdownBeep(false);
    }
  }
}

function updateGame(){
  if(state!==STATE.PLAYING) return;
  frame++; bgScroll+=pipeSpeed*0.5; flapFrame++;
  clouds.forEach(c=>{ c.x-=c.speed; if(c.x<-c.w) c.x=BASE_W+c.w; });
  bird.vy+=GRAVITY; bird.y+=bird.vy;
  bird.angle=Math.max(-0.4,Math.min(Math.PI*0.4,bird.vy*0.07));
  pipeTimer++;
  if(pipeTimer>=PIPE_INTERVAL){ spawnPipe(); pipeTimer=0; }
  for(let i=pipes.length-1;i>=0;i--){
    pipes[i].x-=pipeSpeed;
    if(!pipes[i].scored&&pipes[i].x+PIPE_W<bird.x){
      pipes[i].scored=true; score++; playPoint();
      addScorePopup(bird.x+40,bird.y-30,'+1');
      if(score%10===0&&score!==lastMilestone){
        lastMilestone=score;
        spawnParticles(BASE_W/2,BASE_H/2,40,['#FFD700','#FF4400','#FF8800','#FF00FF','#00FFFF'],100,8);
        addScorePopup(BASE_W/2,BASE_H/3,'🌟 WAAAH! 🌟');
      }
      pipeSpeed=PIPE_SPEED_BASE+score*0.04;
    }
    if(pipes[i].x+PIPE_W<-10) pipes.splice(i,1);
  }
  if(checkCollision()){
    state=STATE.DEAD; gameOverTimer=0;
    playMakaBhosda();  // 🎵 MAKA BHOSDA on death
    addShake(12);
    spawnParticles(bird.x,bird.y,30,['#FFD700','#FF4400','#FF8800','#ffffff'],80,7);
    if(score>highScore){ highScore=score; localStorage.setItem('fma_hs',highScore); }
    stopMusic();
  }
  updateParticles(); updateScorePopups();
  if(shakeAmount>0) shakeAmount*=0.85;
}

// ── HUD ────────────────────────────────────────────────────────
function drawHUD(){
  ctx.textAlign='center';
  ctx.font='bold 36px Arial Black';
  ctx.strokeStyle='#1a0832'; ctx.lineWidth=5; ctx.strokeText(score,BASE_W/2,55);
  ctx.fillStyle='#FFD700'; ctx.fillText(score,BASE_W/2,55);
  ctx.font='bold 14px Arial Black';
  ctx.strokeStyle='#1a0832'; ctx.lineWidth=3; ctx.strokeText('BEST: '+highScore,BASE_W/2,75);
  ctx.fillStyle='#ffaa00'; ctx.fillText('BEST: '+highScore,BASE_W/2,75);
}

// ── Countdown Screen ───────────────────────────────────────────
function drawCountdown(){
  drawBackground(bgScroll);
  // Bird hovering in center
  const hoverY=BASE_H*0.4+Math.sin(Date.now()*0.004)*10;
  drawMaka(BASE_W/2,hoverY,0,frame,false);

  // Dark overlay
  ctx.fillStyle='rgba(0,0,0,0.35)';
  ctx.fillRect(0,0,BASE_W,BASE_H);

  const progress=countdownTimer/COUNTDOWN_FRAMES;
  const num=countdownValue;
  const scale2=1+0.4*(1-progress); // shrinks as timer progresses
  const alpha=Math.max(0, progress<0.7 ? 1 : 1-(progress-0.7)/0.3);

  ctx.save();
  ctx.translate(BASE_W/2, BASE_H/2);
  ctx.scale(scale2,scale2);
  ctx.globalAlpha=alpha;

  // Glow circle
  const grad=ctx.createRadialGradient(0,0,10,0,0,80);
  grad.addColorStop(0,'rgba(255,180,0,0.6)');
  grad.addColorStop(1,'rgba(255,100,0,0)');
  ctx.fillStyle=grad;
  ctx.beginPath(); ctx.arc(0,0,80,0,Math.PI*2); ctx.fill();

  ctx.textAlign='center';
  ctx.font='bold 100px Arial Black';
  ctx.strokeStyle='#8B2200'; ctx.lineWidth=8;
  ctx.strokeText(num,0,38);
  ctx.fillStyle='#FFD700';
  ctx.fillText(num,0,38);

  ctx.restore();
  ctx.globalAlpha=1;

  // "GET READY" text
  ctx.textAlign='center';
  ctx.font='bold 20px Arial Black';
  ctx.strokeStyle='#1a0832'; ctx.lineWidth=4;
  ctx.strokeText('GET READY!',BASE_W/2,BASE_H*0.25);
  ctx.fillStyle='#ffffff';
  ctx.fillText('GET READY!',BASE_W/2,BASE_H*0.25);
}

// ── Title Screen ───────────────────────────────────────────────
let titleFirstDraw = true;
function drawTitleScreen(){
  if(titleFirstDraw){
    titleFirstDraw=false;
    playModiJi(); // 🎵 Modi ji plays once on title screen
  }
  titleBounce+=0.05;
  bgScroll+=0.5;
  drawBackground(bgScroll);
  const demoY=BASE_H*0.35+Math.sin(titleBounce)*20;
  drawMaka(BASE_W*0.5,demoY,Math.sin(titleBounce)*0.15,frame,false);
  if(frame%15===0) spawnParticles(BASE_W*0.5+(Math.random()-0.5)*60,demoY+(Math.random()-0.5)*60,3,['#FFD700','#FF8800','#FF00FF'],20,2);
  updateParticles(); drawParticles();

  ctx.textAlign='center';
  ctx.shadowColor='#FF4400'; ctx.shadowBlur=20;
  ctx.font='bold 34px Arial Black';
  ctx.strokeStyle='#1a0832'; ctx.lineWidth=6;
  ctx.strokeText('FLAPPY',BASE_W/2,90);
  ctx.strokeText('MAKA AAAAAG!',BASE_W/2,128);
  ctx.fillStyle='#FFD700'; ctx.fillText('FLAPPY',BASE_W/2,90);
  ctx.fillStyle='#FF6600'; ctx.fillText('MAKA AAAAAG!',BASE_W/2,128);
  ctx.shadowBlur=0;
  ctx.font='bold 13px Arial Black';
  ctx.strokeStyle='#1a0832'; ctx.lineWidth=3;
  ctx.strokeText('A BOLLYWOOD PARODY ADVENTURE',BASE_W/2,150);
  ctx.fillStyle='#ffcc44'; ctx.fillText('A BOLLYWOOD PARODY ADVENTURE',BASE_W/2,150);

  const pulse=0.85+0.15*Math.sin(titleBounce*2);
  ctx.save(); ctx.translate(BASE_W/2,BASE_H*0.72); ctx.scale(pulse,pulse);
  const btnGrad=ctx.createLinearGradient(-100,-27,100,27);
  btnGrad.addColorStop(0,'#FF6600'); btnGrad.addColorStop(0.5,'#FF8800'); btnGrad.addColorStop(1,'#FF4400');
  ctx.fillStyle=btnGrad;
  ctx.beginPath(); ctx.roundRect(-100,-27,200,55,12); ctx.fill();
  ctx.strokeStyle='#FFD700'; ctx.lineWidth=3; ctx.stroke();
  ctx.font='bold 20px Arial Black';
  ctx.strokeStyle='#8B2200'; ctx.lineWidth=4;
  ctx.strokeText('▶  SHURU KARO!',0,8);
  ctx.fillStyle='#FFFFFF'; ctx.fillText('▶  SHURU KARO!',0,8);
  ctx.restore();

  ctx.font='12px Arial'; ctx.fillStyle='rgba(255,220,150,0.8)';
  ctx.fillText('Tap • Click • Press SPACE',BASE_W/2,BASE_H*0.72+45);

  if(highScore>0){
    ctx.font='bold 15px Arial Black';
    ctx.strokeStyle='#1a0832'; ctx.lineWidth=3;
    ctx.strokeText('🏆 BEST: '+highScore,BASE_W/2,BASE_H-110);
    ctx.fillStyle='#FFD700'; ctx.fillText('🏆 BEST: '+highScore,BASE_W/2,BASE_H-110);
  }
  ctx.font='10px Arial'; ctx.fillStyle='rgba(255,180,100,0.6)';
  ctx.fillText('Fan-made parody · Original characters & audio',BASE_W/2,BASE_H-90);
}

// ── Game Over Screen ───────────────────────────────────────────
function drawGameOverScreen(){
  gameOverTimer++;
  ctx.fillStyle='rgba(0,0,0,0.65)'; ctx.fillRect(0,0,BASE_W,BASE_H);
  const t=Math.min(gameOverTimer/40,1);
  ctx.save(); ctx.translate(BASE_W/2,BASE_H/2); ctx.scale(t,t);
  const panW=280,panH=260;
  const panGrad=ctx.createLinearGradient(-panW/2,-panH/2,panW/2,panH/2);
  panGrad.addColorStop(0,'#2a0840'); panGrad.addColorStop(1,'#1a0420');
  ctx.fillStyle=panGrad;
  ctx.beginPath(); ctx.roundRect(-panW/2,-panH/2,panW,panH,16); ctx.fill();
  ctx.strokeStyle='#FF4400'; ctx.lineWidth=3; ctx.stroke();
  ctx.shadowColor='#FF4400'; ctx.shadowBlur=15;
  ctx.font='bold 36px Arial Black'; ctx.textAlign='center';
  ctx.strokeStyle='#8B0000'; ctx.lineWidth=5;
  ctx.strokeText('GAME OVER!',0,-80);
  ctx.fillStyle='#FF4400'; ctx.fillText('GAME OVER!',0,-80);
  ctx.shadowBlur=0;
  ctx.font='bold 18px Arial Black'; ctx.fillStyle='#FFD700';
  ctx.fillText('"MAKA BHOSDA!"',0,-45);
  ctx.font='bold 16px Arial Black'; ctx.fillStyle='#ffcc88'; ctx.fillText('SCORE',0,-10);
  ctx.font='bold 52px Arial Black';
  ctx.strokeStyle='#8B4500'; ctx.lineWidth=5; ctx.strokeText(score,0,40);
  ctx.fillStyle='#FFD700'; ctx.fillText(score,0,40);
  if(score>=highScore&&score>0){ ctx.font='bold 16px Arial Black'; ctx.fillStyle='#FF6600'; ctx.fillText('🌟 NEW BEST! 🌟',0,65); }
  else { ctx.font='14px Arial Black'; ctx.fillStyle='#ffaa44'; ctx.fillText('BEST: '+highScore,0,65); }
  if(gameOverTimer>40){
    const rpulse=0.92+0.08*Math.sin(gameOverTimer*0.1);
    ctx.save(); ctx.translate(0,105); ctx.scale(rpulse,rpulse);
    ctx.fillStyle='#FF6600';
    ctx.beginPath(); ctx.roundRect(-90,-20,180,40,10); ctx.fill();
    ctx.strokeStyle='#FFD700'; ctx.lineWidth=2; ctx.stroke();
    ctx.font='bold 16px Arial Black';
    ctx.strokeStyle='#8B2200'; ctx.lineWidth=3;
    ctx.strokeText('🔄 TAP TO RETRY',0,6);
    ctx.fillStyle='white'; ctx.fillText('🔄 TAP TO RETRY',0,6);
    ctx.restore();
  }
  ctx.restore();
}

// ── Main Loop ──────────────────────────────────────────────────
// Lock game logic to 60fps regardless of monitor refresh rate (120Hz/144Hz
// screens fire requestAnimationFrame faster, which made the game run too fast).
const FRAME_TIME = 1000 / 60;
let frameAcc = 0, lastFrameStamp = 0;
function gameLoop(now){
  requestAnimationFrame(gameLoop);
  if(lastFrameStamp) frameAcc += now - lastFrameStamp;
  else frameAcc = FRAME_TIME; // first frame runs immediately
  lastFrameStamp = now;
  if(frameAcc < FRAME_TIME - 0.5) return;              // not time for a 60fps step yet
  frameAcc = Math.min(frameAcc - FRAME_TIME, FRAME_TIME * 2); // consume one step, cap leftover (no fast-forward after tab switch)
  frame++;
  const shakeX=shakeAmount>0.5?(Math.random()-0.5)*shakeAmount:0;
  const shakeY=shakeAmount>0.5?(Math.random()-0.5)*shakeAmount:0;
  ctx.save();
  if(shakeAmount>0.5) ctx.translate(shakeX,shakeY);

  if(state===STATE.TITLE){
    drawTitleScreen();
  } else if(state===STATE.COUNTDOWN){
    updateCountdown();
    drawCountdown();
  } else {
    drawBackground(bgScroll);
    pipes.forEach(p=>drawPipe(p.x-PIPE_W/2+28,p.topH,p.gap));
    drawParticles();
    const isDead=state===STATE.DEAD;
    drawMaka(bird.x,bird.y,isDead?Math.PI*0.3:bird.angle,flapFrame,isDead);
    if(state===STATE.PLAYING){ updateGame(); drawHUD(); drawScorePopups(); }
    else if(state===STATE.DEAD){ updateParticles(); updateScorePopups(); drawHUD(); drawGameOverScreen(); }
  }

  ctx.restore();
}

requestAnimationFrame(gameLoop);
